// Transform business data for knowledge graph entity
const businessData = $json.business_data;

return {
  json: {
    ...$json, // Pass through all existing fields
    graph_entity: {
      name: $json.business_name,
      type: "Business",
      attributes: {
        // Unique identifiers
        apify_place_id: $json.apify_place_id,
        place_url: businessData.overview?.url,

        // Core business info
        category: businessData.overview?.category,
        city: businessData.overview?.city,
        state: businessData.overview?.state,
        address: `${businessData.overview?.street || ''}, ${businessData.overview?.city || ''}, ${businessData.overview?.state || ''}`.trim(),
        postal_code: businessData.overview?.postalCode,

        // Contact
        phone: businessData.contact?.phone,
        website: businessData.contact?.website,
        email: businessData.contact?.email,

        // Metrics
        rating: businessData.rating?.totalScore,
        review_count: businessData.rating?.reviewsCount,

        // Status
        is_advertisement: businessData.overview?.isAdvertisement,
        temporarily_closed: businessData.overview?.temporarilyClosed,
        permanently_closed: businessData.overview?.permanentlyClosed,

        // Metadata
        search_string: $json.search_string,
        execution_id: $json.execution_id,
        last_updated: new Date().toISOString()
      },

      // Optional: Define relationships for graph
      relationships: [
        {
          type: "LOCATED_IN",
          target_entity: {
            type: "City",
            name: businessData.overview?.city || "Unknown"
          }
        },
        {
          type: "BELONGS_TO_CATEGORY",
          target_entity: {
            type: "BusinessCategory",
            name: businessData.overview?.category || "Uncategorized"
          }
        }
      ]
    }
  }
};
